// Parse the Claude response and merge it with the original intake fields
const intake = $('Set Intake Fields').item.json;
const raw = $json.content?.[0]?.text || '{}';

let parsed = {
  practice_area: 'other',
  case_summary: 'Failed to parse AI response',
  qualified: false,
  urgency: 'low',
  time_sensitivity_note: '',
  conflict_check_flag: false,
  opposing_party: '',
  recommended_team: 'Intake review',
  decline_reason: 'AI parsing failed; route to manual review',
  missing_info: []
};

try {
  const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed.case_summary = 'AI returned malformed JSON: ' + raw.slice(0, 200);
}

const isQualified = parsed.qualified === true;
const missingInfo = Array.isArray(parsed.missing_info) ? parsed.missing_info.join(' | ') : '';

return [{
  json: {
    ...intake,
    practice_area: parsed.practice_area || 'other',
    case_summary: parsed.case_summary || '',
    qualified: isQualified,
    isQualified,
    urgency: parsed.urgency || 'low',
    time_sensitivity_note: parsed.time_sensitivity_note || '',
    conflict_check_flag: parsed.conflict_check_flag === true,
    opposing_party: parsed.opposing_party || '',
    recommended_team: parsed.recommended_team || 'Intake review',
    decline_reason: parsed.decline_reason || '',
    missing_info: missingInfo
  }
}];
